import AppKit

/// Image assets embedded as base64-encoded PNG bytes so they load identically
/// whether the app is built via Xcode (asset catalog present) or via SwiftPM +
/// build-app.sh (no asset catalog — `actool` needs full Xcode). Decoded once at
/// runtime with `NSImage(data:)`; no main-bundle lookup, no loose files.
enum HushAssets {
    /// The menu-bar glyph (the "shush" mark). Rendered as a template image so it
    /// adapts to light/dark menu bars. Source: MenuBarIcon.imageset/menubar_icon@2x.png.
    static let menuBarIcon: NSImage? = {
        guard let image = decode(menuBarBase64) else { return nil }
        image.size = NSSize(width: 18, height: 18)
        image.isTemplate = true
        return image
    }()

    /// The colored app logo shown in the popover header. Source: HushIcon.imageset/icon_72.png.
    static let appLogo: NSImage? = decode(logoBase64)

    private static func decode(_ base64: String) -> NSImage? {
        guard let data = Data(base64Encoded: base64) else { return nil }
        return NSImage(data: data)
    }

    private static let menuBarBase64 = ""

    private static let logoBase64 = ""
}
